values
	("LOC_PEDIA_CONCEPTS_PAGEGROUP_HD_NAME",                                                     "Harmony in Diversity"),
	-- 概述
	("LOC_PEDIA_CONCEPTS_PAGE_HD_OVERVIEW_PAGE_CHAPTER_CONTENT_TITLE",                           "Overview"),
	("LOC_PEDIA_CONCEPTS_PAGE_HD_OVERVIEW_PAGE_CHAPTER_HD_DESIGN_PHILOSOPHY_TITLE",              "Design Philosophy"),
	("LOC_PEDIA_CONCEPTS_PAGE_HD_OVERVIEW_PAGE_CHAPTER_HD_DESIGN_PHILOSOPHY_PARA_1",             "As the successor to the first-generation Harmony in Diversity, Harmony in Diversity 2.0 inherits and further evolves the mod’s core principle of diversity. This iteration introduces significantly more [ICON_SCIENCE] Technologies, [ICON_CULTURE] Civics, [ICON_GREATPERSON] Great People, buildings, and policies than its predecessor—dramatically deepening gameplay possibilities and unlocking new strategic potential for every game element.[NEWLINE][NEWLINE]For example:[NEWLINE][NEWLINE]Great Artists and Great Musicians now appear in earlier eras.[NEWLINE][NEWLINE]All Cultural Great Persons now scale their [ICON_CULTURE] Culture/[ICON_TOURISM] Tourism outputs by their era of origin, creating smoother progression for cultural or tourism victories.[NEWLINE][NEWLINE]While Harmony in Diversity 1.0 emphasized early-game balance, 2.0 strategically enhances mid-to-late game with engaging mechanics and meaningful power spikes. This ensures both victory-focused players and those seeking entertainment at every stage enjoy a fulfilling experience.[NEWLINE][NEWLINE]In this reimagined era of Harmony in Diversity 2.0, all players can rediscover their passion for Civilization VI."),
	("LOC_PEDIA_CONCEPTS_PAGE_HD_OVERVIEW_PAGE_CHAPTER_HD_NEW_CONTENTS_TITLE",                   "2.0 New Content"),
	("LOC_PEDIA_CONCEPTS_PAGE_HD_OVERVIEW_PAGE_CHAPTER_HD_NEW_CONTENTS_PARA_1",                  "Expanded [ICON_GREATPERSON] Great Persons: New early-era figures across more specialist types for cohesive gameplay.[NEWLINE][NEWLINE]More [ICON_SCIENCE] Technologies & [ICON_CULTURE] Civics: Enrich every era while integrating real-world historical elements.[NEWLINE][NEWLINE]Revitalized Civilizations & Leaders: Historically authentic, gameplay-significant reworks for previously underpowered factions.[NEWLINE][NEWLINE]Redesigned Policy System: Diplomatic policies merged into Cultural Policies—creating clearer, more unique policy boundaries.[NEWLINE][NEWLINE]New Specialized District: Agrarian Precinct: Unlocks advanced [ICON_FOOD] Food production methods. This also showcases our new district-design capabilities, opening doors for future innovations.[NEWLINE][NEWLINE]Dynamic Systems Interplay: Countless new synergies between mechanics await your discovery!"),
	("LOC_PEDIA_CONCEPTS_PAGE_HD_OVERVIEW_PAGE_CHAPTER_HD_MOD_INTRODUCTION_TITLE",               "Core Module Highlights"),
	("LOC_PEDIA_CONCEPTS_PAGE_HD_OVERVIEW_PAGE_CHAPTER_HD_MOD_INTRODUCTION_PARA_1",              "District Expansion:[NEWLINE]Districts now offer multiple building choices per tier, enabling city specialization.[NEWLINE][NEWLINE]Suzerainty Expansion:[NEWLINE]New Agrarian and Maritime city-states—every playstyle now has allied support.[NEWLINE][NEWLINE]Corporations & Monopolies Expansion:[NEWLINE]Compatible with vanilla Corporations and Leugi’s Monopolies and Corporations mod. Maximize resource value, then leverage products as late-game cultural weapons.[NEWLINE][NEWLINE]Civilization & Leader Expansion:[NEWLINE]More historical factions and rulers for role-playing enthusiasts."),
	-- 概念与术语
	("LOC_PEDIA_CONCEPTS_PAGE_HD_CONCEPTS_PAGE_CHAPTER_CONTENT_TITLE",                           "Concepts and Terminology"),
	("LOC_PEDIA_CONCEPTS_PAGE_HD_CONCEPTS_PAGE_CHAPTER_HD_OVERVIEW_TITLE",                       "Overview"),
	("LOC_PEDIA_CONCEPTS_PAGE_HD_CONCEPTS_PAGE_CHAPTER_HD_OVERVIEW_PARA_1",                      "Harmony in Diversity 2.0 have introduced many new concepts and terms to simplify and unify the game text."),
	("LOC_PEDIA_CONCEPTS_PAGE_HD_CONCEPTS_PAGE_CHAPTER_HD_OVERVIEW_PARA_2",                      "For instance, the ability of the Chinese leader Wu Zetian (Tianshou) is:[NEWLINE][NEWLINE]When you recruit a [ICON_GREATPERSON] Great Person, provide corresponding yield of two copies to all corresponding type districts in your country.[NEWLINE][NEWLINE][NEWLINE]When recruiting a [ICON_GreatScientist] Great Scientist, the corresponding district of [ICON_GreatScientist] Great Scientist is Campus, and the corresponding yield is [ICON_SCIENCE] Science, so the actual effect is:[NEWLINE][NEWLINE]Recruiting a [ICON_GreatScientist] Great Scientist provides +2 [ICON_SCIENCE] Science for all Campus districts in your country.[NEWLINE][NEWLINE]The same applies to other [ICON_GREATPERSON] Great People."),
	("LOC_PEDIA_CONCEPTS_PAGE_HD_CONCEPTS_PAGE_CHAPTER_HD_DISTRICT_YIELDS_TITLE",                "Corresponding Yield of District"),
	("LOC_PEDIA_CONCEPTS_PAGE_HD_CONCEPTS_PAGE_CHAPTER_HD_DISTRICT_YIELDS_PARA_1",               "[ICON_BULLET][ICON_DISTRICT_HOLY_SITE]Holy Site: +1 [ICON_FAITH] Faith[NEWLINE][ICON_BULLET][ICON_DISTRICT_CAMPUS]Campus: +1 [ICON_SCIENCE] Science[NEWLINE][ICON_BULLET][ICON_DISTRICT_THEATER]Theater Square: +1 [ICON_CULTURE] Culture[NEWLINE][ICON_BULLET][ICON_DISTRICT_COMMERCIAL_HUB]Commercial Hub: +3 [ICON_GOLD] Gold[NEWLINE][ICON_BULLET][ICON_DISTRICT_HARBOR]Harbor: +3 [ICON_GOLD] Gold[NEWLINE][ICON_BULLET][ICON_DISTRICT_ENCAMPMENT]Encampment: +1 [ICON_PRODUCTION] Production[NEWLINE][ICON_BULLET][ICON_DISTRICT_INDUSTRIAL_ZONE]Industrial Zone: +1 [ICON_PRODUCTION] Production[NEWLINE][ICON_BULLET][ICON_DISTRICT_GOVERNMENT]Government Plaza: +1 [ICON_CULTURE] Culture[NEWLINE][ICON_BULLET][ICON_DISTRICT_DIPLOMATIC_QUARTER]Diplomatic Quarter: +3 [ICON_GOLD] Gold[NEWLINE][ICON_BULLET][ICON_DISTRICT_CITY_CENTER]City Center: +1 [ICON_PRODUCTION] Production[NEWLINE][ICON_BULLET][ICON_DISTRICT_AQUEDUCT]Cistern: +1 [ICON_FOOD] Food[NEWLINE][ICON_BULLET][ICON_DISTRICT_ENTERTAINMENT_COMPLEX]Entertainment Complex: +3 [ICON_GOLD] Gold[NEWLINE][ICON_BULLET][ICON_DISTRICT_WATER_ENTERTAINMENT_COMPLEX]Water Park: +3 [ICON_GOLD] Gold[NEWLINE][ICON_BULLET][ICON_DISTRICT_DAM]Dam: +1 [ICON_FOOD] Food[NEWLINE][ICON_BULLET][ICON_DISTRICT_CANAL]Canal: +3 [ICON_GOLD] Gold[NEWLINE][ICON_BULLET][ICON_DISTRICT_NEIGHBORHOOD]Neighborhood: +1 [ICON_PRODUCTION] Production[NEWLINE][ICON_BULLET][ICON_DISTRICT_AERODROME]Aerodrome: +3 [ICON_GOLD] Gold[NEWLINE][ICON_BULLET][ICON_DISTRICT_PRESERVE]Preserve: +1 [ICON_FOOD] Food"),
	("LOC_PEDIA_CONCEPTS_PAGE_HD_CONCEPTS_PAGE_CHAPTER_HD_DISTRICT_GPPS_TITLE",                  "Corresponding Great Person of District"),
	("LOC_PEDIA_CONCEPTS_PAGE_HD_CONCEPTS_PAGE_CHAPTER_HD_DISTRICT_GPPS_PARA_1",                 "[ICON_BULLET][ICON_DISTRICT_HOLY_SITE]Holy Site: [ICON_GreatProphet] Great Prophet[NEWLINE][ICON_BULLET][ICON_DISTRICT_CAMPUS]Campus: [ICON_GreatScientist] Great Scientist[NEWLINE][ICON_BULLET][ICON_DISTRICT_THEATER]Theater Square: [ICON_GreatWriter] Great Writer [ICON_GreatArtist] Great Artist [ICON_GreatMusician] Great Musician[NEWLINE][ICON_BULLET][ICON_DISTRICT_COMMERCIAL_HUB]Commercial Hub: [ICON_GreatMerchant] Great Merchant[NEWLINE][ICON_BULLET][ICON_DISTRICT_HARBOR]Harbor: [ICON_GreatAdmiral] Great Admiral[NEWLINE][ICON_BULLET][ICON_DISTRICT_ENCAMPMENT]Encampment: [ICON_GreatGeneral] Great General[NEWLINE][ICON_BULLET][ICON_DISTRICT_INDUSTRIAL_ZONE]Industrial Zone: [ICON_GreatEngineer] Great Engineer"),
	("LOC_PEDIA_CONCEPTS_PAGE_HD_CONCEPTS_PAGE_CHAPTER_HD_GREAT_PERSON_YIELDS_TITLE",            "Corresponding Yield of Great Person"),
	("LOC_PEDIA_CONCEPTS_PAGE_HD_CONCEPTS_PAGE_CHAPTER_HD_GREAT_PERSON_YIELDS_PARA_1",           "[ICON_BULLET][ICON_GreatProphet] Great Prophet: +1 [ICON_FAITH] Faith[NEWLINE][ICON_BULLET][ICON_GreatScientist] Great Scientist: +1 [ICON_SCIENCE] Science[NEWLINE][ICON_BULLET][ICON_GreatWriter] Great Writer: +1 [ICON_CULTURE] Culture[NEWLINE][ICON_BULLET][ICON_GreatArtist] Great Artist: +1 [ICON_CULTURE] Culture[NEWLINE][ICON_BULLET][ICON_GreatMusician] Great Musician: +1 [ICON_CULTURE] Culture[NEWLINE][ICON_BULLET][ICON_GreatMerchant] Great Merchant: +3 [ICON_GOLD] Gold[NEWLINE][ICON_BULLET][ICON_GreatAdmiral] Great Admiral: +3 [ICON_GOLD] Gold[NEWLINE][ICON_BULLET][ICON_GreatGeneral] Great General: +1 [ICON_PRODUCTION] Production[NEWLINE][ICON_BULLET][ICON_GreatEngineer] Great Engineer: +1 [ICON_PRODUCTION] Production"),
	("LOC_PEDIA_CONCEPTS_PAGE_HD_CONCEPTS_PAGE_CHAPTER_HD_CITY_STATE_YIELDS_TITLE",              "Corresponding Yield of City-state"),
	("LOC_PEDIA_CONCEPTS_PAGE_HD_CONCEPTS_PAGE_CHAPTER_HD_CITY_STATE_YIELDS_PARA_1",             "[ICON_BULLET]Religious: +1 [ICON_FAITH] Faith[NEWLINE][ICON_BULLET]Scientific: +1 [ICON_SCIENCE] Science[NEWLINE][ICON_BULLET]Cultural: +1 [ICON_CULTURE] Culture[NEWLINE][ICON_BULLET]Trade: +3 [ICON_GOLD] Gold[NEWLINE][ICON_BULLET]Maritime: +3 [ICON_GOLD] Gold[NEWLINE][ICON_BULLET]Militaristic: +1 [ICON_PRODUCTION] Production[NEWLINE][ICON_BULLET]Industrial: +1 [ICON_PRODUCTION] Production[NEWLINE][ICON_BULLET]Agriculture: +1 [ICON_FOOD] Food"),
