	("LOC_PEDIA_CONCEPTS_PAGE_HD_CONCEPTS_PAGE_CHAPTER_HD_CITY_STATE_DISTRICTS_PARA_1",          "[ICON_BULLET]Religious: [ICON_DISTRICT_HOLY_SITE]Holy Site[NEWLINE][ICON_BULLET]Scientific: [ICON_DISTRICT_CAMPUS]Campus[NEWLINE][ICON_BULLET]Cultural: [ICON_DISTRICT_THEATER]Theater Square[NEWLINE][ICON_BULLET]Trade: [ICON_DISTRICT_COMMERCIAL_HUB]Commercial Hub[NEWLINE][ICON_BULLET]Maritime: [ICON_DISTRICT_HARBOR]Harbor[NEWLINE][ICON_BULLET]Militaristic: [ICON_DISTRICT_ENCAMPMENT]Encampment[NEWLINE][ICON_BULLET]Industrial: [ICON_DISTRICT_INDUSTRIAL_ZONE]Industrial Zone"),
