-- Language: en_US
insert or replace into EnglishText
	(Tag,                                                                               Text)
values
	("LOC_PEDIA_BUILDINGS_PAGE_BUILDING_NILOMETER_HD_CHAPTER_HISTORY_PARA_1",           "The measuring device comes from the Nile gauge in the official scenario ""The Gift of the Nile"". The Nile gauge was a stepped hydraulic device that the Egyptians built along the Nile to regulate agricultural production by observing the water level of the Nile using the steps and the scales on the pillars contained within them. To this day, the remains of such structures can be found on the island of Roda in Cairo and on the island of Elephantine in Aswan. It was not until the opening of the Aswan Dam that the temple of Abu Simbel was saved, but Egyptian water relics like the Nile Instrument officially ended their mission."),
	("LOC_PEDIA_BUILDINGS_PAGE_BUILDING_FAIR_CHAPTER_HISTORY_PARA_1",                   "From the emergence of the division of labour in material production there was an interaction of different substances, and then the exchange of goods followed. Then, because of the division of labour and the geographical nature of the production of goods, people began to form their own bazaars in places that were easily accessible. For a long time, fairs were the main source of access to things that people could not produce themselves, until the emergence of supermarkets.");

--------------------------------------------------------------------------------
-- Language: zh_Hans_CN
insert or replace into LocalizedText
	(Language,      Tag,                                                                                Text)
values
	("zh_Hans_CN",  "LOC_PEDIA_BUILDINGS_PAGE_BUILDING_NILOMETER_HD_CHAPTER_HISTORY_PARA_1",            "测量仪来自官方情景“尼罗河的赠礼”中的尼罗河仪。尼罗河仪是一种阶梯型的水利设施，埃及人在尼罗河边建立这些设施，用阶梯和其中包含的柱子上的刻度观测尼罗河的水位，调节农业生产。到现在，开罗的罗达岛、阿斯旺的埃勒芬蒂尼岛都有这种建筑的遗迹。直到阿斯旺大坝的启用，阿布辛拜勒神庙虽然被拯救，但是像尼罗河仪这些埃及水利遗迹却正式终结了使命。"),
	("zh_Hans_CN",  "LOC_PEDIA_BUILDINGS_PAGE_BUILDING_FAIR_CHAPTER_HISTORY_PARA_1",                    "从物质生产出现分工开始就有了不同物质的交互，然后商品交换随之产生。然后，因为商品生产的分工和地域性，人们开始在交通便利的地方自发的形成集市。在很长一段时间内，集市都是人们获得自己无法生产的东西的主要来源，直到超级市场出现。");

insert or replace into EnglishText
	(Tag,                                                                               Text)
values
	("LOC_PEDIA_LEADERS_PAGE_LEADER_CLEOPATRA_ALT_QUOTE",                               "All strange and terrible events are welcome,But comforts we despise. Our size of sorrow,Proportioned to our cause, must be as greatAs that which makes it."),
	("LOC_AGENDA_PREFER_FOOD_NAME",                                                     "Queen of the Nile"),
	("LOC_AGENDA_QUEEN_OF_THE_NILE_NAME",                                               "Mediterranean's Bride"),
	("LOC_DIPLO_WARNING_LEADER_ANY_REASON_AGENDA_LOW_FOOD",                             "You have done so little that the population of your country is no longer growing. What do your people eat?"),
	("LOC_AGENDA_MAAT_NAME",                                                            "love of Hathor"),
	("LOC_DIPLO_ACCEPT_DECLARE_FRIEND_FROM_HUMAN_LEADER_RAMSES_ANY",                    "It is done. A partnership between the black land of Ra and yours."),
	("LOC_PEDIA_LEADERS_PAGE_LEADER_KUBLAI_KHAN_CHINA_CHAPTER_CAPSULE_BODY",            "Unlike his grandfather, Kublai placed more emphasis on the integration of civilizations and civilizations with each other, and was able to use the leadership abilities of this civilization after conquering the original capitals of other major civilizations."),
	("LOC_PEDIA_LEADERS_PAGE_LEADER_KUBLAI_KHAN_CHINA_CHAPTER_DETAILED_BODY",           "Kublai had additional economic policy slots for a variety of different ways of winning. But he prefers to conquer more civilisations and make them available to him. So you need to actively wage war to conquer more civilisations, which in turn fuels technological, cultural or conquest victories."),
	("LOC_PEDIA_LEADERS_PAGE_LEADER_KUBLAI_KHAN_MONGOLIA_CHAPTER_CAPSULE_BODY",         "Unlike his grandfather, Kublai placed more emphasis on the integration of civilizations and civilizations with each other, and was able to use the leadership abilities of this civilization after conquering the original capitals of other major civilizations."),
	("LOC_PEDIA_LEADERS_PAGE_LEADER_KUBLAI_KHAN_MONGOLIA_CHAPTER_DETAILED_BODY",        "Kublai had additional economic policy slots for a variety of different ways of winning. But he prefers to conquer more civilisations and make them available to him. So you need to actively wage war to conquer more civilisations, which in turn fuels technological, cultural or conquest victories.");
