-- Language: zh_Hans_CN
insert or replace into LocalizedText
	(Language,      Tag,                                                                                Text)
values
	("zh_Hans_CN",  "LOC_PEDIA_LEADERS_PAGE_LEADER_CLEOPATRA_ALT_QUOTE",                                "种种奇事恶事都可接受，但我们就是不要虚无的安慰；悲伤的程度和悲伤的原因成正比，悲伤有多大，取决于造成悲伤的原因。"),
	("zh_Hans_CN",  "LOC_AGENDA_PREFER_FOOD_NAME",                                                      "尼罗河女王"),
	("zh_Hans_CN",  "LOC_AGENDA_QUEEN_OF_THE_NILE_NAME",                                                "地中海新娘"),
	("zh_Hans_CN",  "LOC_DIPLO_WARNING_LEADER_ANY_REASON_AGENDA_LOW_FOOD",                              "你们的人口停止增长，你却毫不作为。看看你的人民在吃什么？"),
	("zh_Hans_CN",  "LOC_AGENDA_MAAT_NAME",                                                             "哈索尔的钟爱"),
	("zh_Hans_CN",  "LOC_DIPLO_ACCEPT_DECLARE_FRIEND_FROM_HUMAN_LEADER_RAMSES_ANY",                     "就这么定了。拉神光耀下的黑土地与你们就此联结绑定。"),
	("zh_Hans_CN",  "LOC_DIPLO_MAKE_PEACE_FROM_AI_LEADER_RAMSES_ANY",                                   "塞赫迈特已经饱尝了鲜血。我们要不要停战？"),
	("zh_Hans_CN",  "LOC_AGENDA_QUEEN_OF_THE_NILE_DESCRIPTION",                                         "喜欢武力更强大的文明，并试图与他们结盟以躲避战争。讨厌军事势力比他们弱小的文明。"),
	("zh_Hans_CN",  "LOC_PEDIA_LEADERS_PAGE_LEADER_KUBLAI_KHAN_CHINA_CHAPTER_CAPSULE_BODY",             "与祖父不同，忽必烈更加强调文明和文明之间的融合，在征服其他主要文明的原始首都之后，能够使用这个文明的领袖能力。"),
	("zh_Hans_CN",  "LOC_PEDIA_LEADERS_PAGE_LEADER_KUBLAI_KHAN_CHINA_CHAPTER_DETAILED_BODY",            "忽必烈拥有额外的经济政策槽位，适合各种不同的胜利方式。但是他更倾向于征服更多的文明，让他们为自己所用。所以你需要积极发动战争，征服更多的文明，进而助力科技、文化或征服胜利。"),
	("zh_Hans_CN",  "LOC_PEDIA_LEADERS_PAGE_LEADER_KUBLAI_KHAN_MONGOLIA_CHAPTER_CAPSULE_BODY",          "与祖父不同，忽必烈更加强调文明和文明之间的融合，在征服其他主要文明的原始首都之后，能够使用这个文明的领袖能力。"),
	("zh_Hans_CN",  "LOC_PEDIA_LEADERS_PAGE_LEADER_KUBLAI_KHAN_MONGOLIA_CHAPTER_DETAILED_BODY",         "忽必烈拥有额外的经济政策槽位，适合各种不同的胜利方式。但是他更倾向于征服更多的文明，让他们为自己所用。所以你需要积极发动战争，征服更多的文明，进而助力科技、文化或征服胜利。"),
	("zh_Hans_CN",  "LOC_PEDIA_CONCEPTS_PAGE_DIPLO_5_CHAPTER_CONTENT_PARA_1",                           "完成文艺复兴时代的“外交部门”市政可解锁间谍单位的使用，而建成外交区或者使用总督阿玛尼可更早获得间谍。这是一种特种单位，可潜伏暗中观察和收集信息，也可执行具有进攻性、破坏性的任务。[NEWLINE][NEWLINE]您可以在任何城市招募间谍，但无法购买，除非拥有阿玛尼的“鹰巢”升级（可通过 [ICON_FAITH] 信仰值购买间谍）。间谍的造价是80+10生产力花费。NEWLINE][NEWLINE]间谍最初为“新手间谍”等级，成功完成进攻性任务或反间谍过程中俘获敌方间谍后即可升级。达到第2级时间谍便能获得1次升级强化，称作探员，第3级是特务，第4级为王牌间谍。间谍的升级加点各有不同，有的需要出击执行进攻性任务才能体现价值，有的是反间谍或者后勤作用，而有的升级方向则可以作为斥候配合军事、探索行动。"),
	("zh_Hans_CN",  "LOC_PEDIA_CONCEPTS_PAGE_DIPLO_5_CHAPTER_CONTENT_PARA_2",                           "间谍的移动方式与其他单位不同。他们使用自己的方式在城市和城市之间移动。间谍移动消耗3回合基础时间，如果目的地有便利区域（港口、商业中心、学院、剧院广场、运河和航空港）可进一步缩短时间，但他们由于同盟协定无法移动至当前盟友的城市。驻扎在城市中后，间谍便可出击，开始执行任务。[NEWLINE][NEWLINE]任务包括盗取科技提升、暗杀总督，或单纯提升外交能见度。每种任务都需要花费一定时间，产生的结果也不尽相同。您的间谍可能会被杀死或俘虏；也可能任务失败但却并未暴露；最好的结果便是成功完成任务且未暴露；你可随时选中正在执行任务的间谍命令其终止行动。每个任务具有五个属性，如下[NEWLINE][NEWLINE]基础难度等级：难度等级数字越大，任务越难，难度13为中间线，无其他影响的任务初始成功率约50%。[NEWLINE][NEWLINE]进攻间谍等级增益：在和而不同中每个间谍等级可以+3级成功率。[NEWLINE][NEWLINE]戒备等级减益：设置了文明对不同进攻性任务的警戒程度，相当于额外的难度，数字越大难度越高。[NEWLINE][NEWLINE]防守间谍等级减益：派专门的间谍防守城市时，对不同任务的鉴别能力，可降低进攻方的成功率。[NEWLINE][NEWLINE]基础回合数：是指任务的耗时，间谍任务最少要消耗实际1回合的时间。间谍的语言学家升级/总督阿玛尼的伪装升级/建立外交办各可缩短25%的任务时间；如文化成为某外国文明主流，在该文明的间谍任务可缩短15%（以上手段缩短任务时间后，实际回合数将取整）。[NEWLINE][NEWLINE]常规的攻击任务（从左到右→任务名/任务内容：基础回合数/基础难度/进攻间谍等级增益/戒备等级减益/防守间谍等级减益/任务解释）：[NEWLINE][NEWLINE]窃取科技提升：4回合，10/3/0/5，在学院进行，从该文明已经研究完的科技和获得过尤里卡的科技中偷取一个随机尤里卡，前提是您的文明未掌握该科技的尤里卡。[NEWLINE][NEWLINE]煽动骚乱：4回合，11/3/0/5，在市中心进行，暂时降低该城市的忠诚度（基础为降低55点，该间谍每有一个间谍升级则多降低15点），使其城市产出下降并面临转变为自由城市的风险。[NEWLINE][NEWLINE]捏造丑闻：8回合，13/3/0/0，在城邦市中心进行，使城邦自发驱逐其他文明已派遣的使者。和而不同修改了除去使者的公式以增加收益（基础为驱逐5个，该间谍每有一个间谍升级则多驱逐2个）。[NEWLINE][NEWLINE]盗取巨作：13/3/3/5/6回合，在剧院广场偷取目标巨作（如目标剧院广场藏有巨作，但间谍任务面板显示“没有可偷取的巨作”请检查你是否具备空的对应巨作槽位）。[NEWLINE][NEWLINE]抽取资金：6回合，14/3/3/5，在商业中心进行，间谍唬骗数个回合，获得相同回合数的该城市金币产出。[NEWLINE][NEWLINE]破坏生产：6回合，17/3/3/5，在工业区进行，毁坏该工业区内的建筑物，使其生产建造的能力下降。[NEWLINE][NEWLINE]爆破堤坝：6回合，18/3/3/5，在堤坝进行，毁坏堤坝引发大洪水，并攻击该堤坝所属河流的泛滥平原上的区域、建筑。[NEWLINE][NEWLINE]陷害总督：8回合，19/3/3/5，在市中心进行，使总督被陷害离开一段时间，然后需要重新就职（基础为陷害5回合，该间谍每有一个间谍升级则多陷害1个回合）。[NEWLINE][NEWLINE]破坏火箭研究：16回合，20/3/6/5，在宇航中心进行，使宇航中心被炸毁，暂停宇航中心正在进行的项目。[NEWLINE][NEWLINE]特殊任务：[NEWLINE][NEWLINE]获取信息源：无额外难度，必定成功，基础时间2回合，为该城市的间谍任务+2级成功率，持续12回合[NEWLINE][NEWLINE]建立情报站：无额外难度，必定成功，基础时间4回合，暂时提升1~2个外交能见度。[NEWLINE][NEWLINE]据说，电脑控制的文明并不会使用捏造丑闻、煽动骚乱这两个间谍任务。"),
	("zh_Hans_CN",  "LOC_PEDIA_CONCEPTS_PAGE_DIPLO_5_CHAPTER_CONTENT_PARA_3",                           "建造外交区和外交区建筑，任用总督阿玛尼并获得“鹰巢”升级可获得额外间谍容量。选择法国领袖凯瑟琳·德·美第奇（黑王后）和美国领袖可获得额外的间谍。");